import React, { useState } from 'react';
import { Outlet, Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { useNotifications } from '../contexts/NotificationContext';
import {
  Home,
  Users,
  Briefcase,
  FileText,
  Calendar,
  Bell,
  MessageSquare,
  User,
  Settings,
  LogOut,
  Menu,
  X,
  BookOpen,
  Award,
  BarChart3,
  Shield
} from 'lucide-react';
import ThemeToggle from './ThemeToggle';

const Layout = () => {
  const { user, logout } = useAuth();
  const { unreadCount } = useNotifications();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [profileDropdownOpen, setProfileDropdownOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const getNavigationItems = () => {
    const baseItems = [
      {
        name: 'Dashboard',
        href: '/dashboard',
        icon: Home,
        current: location.pathname === '/dashboard',
      },
      {
        name: 'Profile',
        href: '/profile',
        icon: User,
        current: location.pathname === '/profile',
      },
      {
        name: 'Messages',
        href: '/messages',
        icon: MessageSquare,
        current: location.pathname.startsWith('/messages'),
      },
      {
        name: 'Notifications',
        href: '/notifications',
        icon: Bell,
        current: location.pathname === '/notifications',
        badge: unreadCount > 0 ? unreadCount : null,
      },
      {
        name: 'Settings',
        href: '/settings',
        icon: Settings,
        current: location.pathname === '/settings',
      },
    ];

    const roleSpecificItems = [];

    if (user?.role === 'student') {
      roleSpecificItems.push(
        {
          name: 'Alumni Directory',
          href: '/alumni',
          icon: Users,
          current: location.pathname === '/alumni',
        },
        {
          name: 'Jobs',
          href: '/jobs',
          icon: Briefcase,
          current: location.pathname.startsWith('/jobs'),
        },
        {
          name: 'MOUs',
          href: '/mou',
          icon: FileText,
          current: location.pathname.startsWith('/mou'),
        },
        {
          name: 'Events',
          href: '/events',
          icon: Calendar,
          current: location.pathname.startsWith('/events'),
        },
        {
          name: 'Notices',
          href: '/notices',
          icon: BookOpen,
          current: location.pathname.startsWith('/notices'),
        }
      );
    }

    if (user?.role === 'alumni') {
      roleSpecificItems.push(
        {
          name: 'Student Directory',
          href: '/alumni',
          icon: Users,
          current: location.pathname === '/alumni',
        },
        {
          name: 'Jobs',
          href: '/jobs',
          icon: Briefcase,
          current: location.pathname.startsWith('/jobs'),
        },
        {
          name: 'Post Job',
          href: '/jobs/post',
          icon: Briefcase,
          current: location.pathname === '/jobs/post',
        },
        {
          name: 'MOUs',
          href: '/mou',
          icon: FileText,
          current: location.pathname.startsWith('/mou'),
        },
        {
          name: 'Events',
          href: '/events',
          icon: Calendar,
          current: location.pathname.startsWith('/events'),
        },
        {
          name: 'Notices',
          href: '/notices',
          icon: BookOpen,
          current: location.pathname.startsWith('/notices'),
        }
      );
    }

    if (user?.role === 'admin') {
      roleSpecificItems.push(
        {
          name: 'User Management',
          href: '/admin/users',
          icon: Users,
          current: location.pathname === '/admin/users',
        },
        {
          name: 'Job Management',
          href: '/admin/jobs',
          icon: Briefcase,
          current: location.pathname === '/admin/jobs',
        },
        {
          name: 'MOU Management',
          href: '/admin/mou',
          icon: FileText,
          current: location.pathname === '/admin/mou',
        },
        {
          name: 'Event Management',
          href: '/admin/events',
          icon: Calendar,
          current: location.pathname === '/admin/events',
        },
        {
          name: 'Notice Management',
          href: '/admin/notices',
          icon: BookOpen,
          current: location.pathname === '/admin/notices',
        },
        {
          name: 'Analytics',
          href: '/admin/analytics',
          icon: BarChart3,
          current: location.pathname === '/admin/analytics',
        }
      );
    }

    return [...baseItems, ...roleSpecificItems];
  };

  const navigationItems = getNavigationItems();
  const sidebarWidthClass = isCollapsed ? 'w-20' : 'w-64';
  const contentMarginClass = isCollapsed ? 'lg:ml-20' : 'lg:ml-64';

  return (
    <div className="group flex h-screen app-shell overflow-x-hidden">
      {/* Mobile sidebar backdrop */}
      {sidebarOpen && (
        <div
          className="fixed inset-0 z-40 bg-slate-950/65 lg:hidden"
          onClick={() => setSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <div className={`fixed inset-y-0 left-0 z-50 transform transition-all duration-300 ease-in-out ${sidebarWidthClass} lg:static lg:inset-0 lg:shadow-none ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'} lg:translate-x-0 sidebar-panel scrollbar-thin overflow-hidden lg:overflow-y-auto lg:h-screen lg:sticky top-0 lg:flex-shrink-0`}>
        <div className="flex flex-col h-full min-h-screen">
          {/* Logo */}

  <div className="flex items-center justify-between h-16 px-4 sidebar-logo">
    <div className="flex items-center min-w-0 gap-3">
      <Award className="w-7 h-7 text-white flex-shrink-0" />
      <span className={`ml-3 truncate transition-all duration-200 text-lg font-bold text-white ${isCollapsed ? 'hidden lg:block' : 'block'}`}>
        Alumni Portal
      </span>
    </div>
    {/* Collapse toggle (desktop) */}
    <button
      onClick={() => setIsCollapsed(!isCollapsed)}
      className="lg:block hidden p-2 rounded-2xl text-slate-300 hover:text-white hover:bg-slate-900/40 transition-all duration-200"
      title={isCollapsed ? "Expand sidebar" : "Collapse sidebar"}
    >
      {isCollapsed ? <Menu className="w-5 h-5" /> : <X className="w-5 h-5" />}
    </button>
    {/* Mobile close */}
    <button
      onClick={() => setSidebarOpen(false)}
      className="lg:hidden p-2 rounded-2xl text-slate-300 hover:text-white hover:bg-slate-900/40 transition-all duration-200"
    >
      <X className="w-5 h-5" />
    </button>
  </div>

          {/* Navigation */}
          <nav className="flex-1 px-4 py-6 space-y-2 overflow-y-auto">
            {navigationItems.map((item) => {
              const Icon = item.icon;
              return (
                <Link
                  key={item.name}
                  to={item.href}
                  className={`sidebar-item ${item.current ? 'sidebar-item-active' : 'sidebar-item-inactive'}`}
                  onClick={() => setSidebarOpen(false)}
                  title={item.name}
                >
                  <div className="flex items-center truncate gap-3">
                    <Icon className={`sidebar-icon ${item.current ? 'text-white' : ''}`} />
                    <span className={`truncate transition-opacity duration-200 ${isCollapsed ? 'opacity-0 w-0 lg:hidden' : 'block'}`}>
                      {item.name}
                    </span>
                  </div>
                  {item.badge && (
                    <span className="sidebar-badge">
                      {item.badge > 99 ? '99+' : item.badge}
                    </span>
                  )}
                </Link>
              );
            })}
          </nav>

          {/* User info */}
          <div className="px-4 py-4 mt-auto border-t border-slate-800/70 bg-slate-900/80 rounded-t-3xl">
            <div className="flex items-center gap-3">
              <div className="flex-1">
                <p className="text-sm font-semibold text-white">
                  {user?.name}
                </p>
                <p className="text-xs text-slate-400 capitalize">
                  {user?.role}
                </p>
              </div>
              <button
                onClick={handleLogout}
                className="p-2 rounded-2xl text-slate-300 hover:text-white hover:bg-slate-900/50 transition-all duration-200"
                title="Logout"
              >
                <LogOut className="w-4 h-4" />
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Main content */}
      <div className={`flex flex-col flex-1 relative z-10 overflow-hidden min-h-0 ${contentMarginClass}`}>
        {/* Top bar */}
        <header className="app-header">
          <div className="flex items-center justify-between h-16 px-4 sm:px-6 lg:px-8">
            {/* Mobile menu button */}
            <button
              onClick={() => setSidebarOpen(true)}
              className="lg:hidden p-2 rounded-2xl text-slate-500 hover:text-slate-900 dark:text-slate-300 dark:hover:text-white hover:bg-slate-100 dark:hover:bg-slate-800 transition-all duration-200"
            >
              <Menu className="w-6 h-6" />
            </button>

            {/* Page title */}
            <div className="flex-1">
              <h1 className="text-lg font-semibold text-slate-900 dark:text-slate-100">
                {navigationItems.find(item => item.current)?.name || 'Dashboard'}
              </h1>
            </div>

            {/* Right side items */}
            <div className="flex items-center space-x-4">
              {/* Notifications */}
              <Link
                to="/notifications"
                className="relative p-2 rounded-2xl text-slate-500 hover:text-slate-900 dark:text-slate-300 dark:hover:text-white hover:bg-slate-100 dark:hover:bg-slate-800 transition-all duration-200"
              >
                <Bell className="w-5 h-5" />
                {unreadCount > 0 && (
                  <span className="absolute top-1 right-1 w-2 h-2 bg-rose-500 rounded-full shadow-glow"></span>
                )}
              </Link>

              {/* Theme toggle */}
              <ThemeToggle />

              {/* Profile dropdown */}

              <div className="relative">
                <button
                  onClick={() => setProfileDropdownOpen(!profileDropdownOpen)}
                  className="flex items-center space-x-3 rounded-2xl border border-slate-200/80 bg-white/80 px-3 py-2 shadow-sm transition-all duration-200 hover:shadow-md dark:border-slate-700/70 dark:bg-slate-900/80"
                >
                  <div className="w-9 h-9 bg-gradient-to-br from-indigo-500 to-blue-600 rounded-full flex items-center justify-center text-white text-sm font-semibold">
                    {user?.name?.charAt(0)?.toUpperCase()}
                  </div>
                  <span className="hidden md:block text-sm font-medium text-slate-700 dark:text-slate-100">
                    {user?.name}
                  </span>
                </button>

                {profileDropdownOpen && (
                  <div className="absolute right-0 mt-2 w-48 bg-slate-50 dark:bg-slate-900/95 rounded-3xl shadow-xl border border-slate-200/70 dark:border-slate-700/70 py-1 z-50">
                    <Link
                      to="/profile"
                      className="dropdown-item"
                      onClick={() => setProfileDropdownOpen(false)}
                    >
                      <User className="w-4 h-4 inline mr-2" />
                      Profile
                    </Link>
                    <Link
                      to="/settings"
                      className="dropdown-item"
                      onClick={() => setProfileDropdownOpen(false)}
                    >
                      <Settings className="w-4 h-4 inline mr-2" />
                      Settings
                    </Link>
                    <button
                      onClick={handleLogout}
                      className="dropdown-item w-full text-left"
                    >
                      <LogOut className="w-4 h-4 inline mr-2" />
                      Logout
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </header>

        {/* Page content */}
<main className="flex-1 p-6 overflow-y-auto">
          <Outlet />
        </main>
      </div>
    </div>
  );
};

export default Layout;
